lt type: \" << ResultVT << \"\\n\");\n      switch (getTypeAction(ResultVT)) {\n      case TargetLowering::TypeLegal:\n        LLVM_DEBUG(dbgs() << \"Legal result type\\n\");\n        break;\n      case TargetLowering::TypeScalarizeScalableVector:\n        report_fatal_error(\n            \"Scalarization of scalable vectors is not supported.\");\n      // The following calls must take care of *all* of the node's results,\n      // not just the illegal result they were passed (this includes results\n      // with a legal type).  Results can be remapped using ReplaceValueWith,\n      // or their promoted/expanded/etc values registered in PromotedIntegers,\n      // ExpandedIntegers etc.\n      case TargetLowering::TypePromoteInteger:\n        PromoteIntegerResult(N, i);\n        Changed = true;\n        goto NodeDone;\n      case TargetLowering::TypeExpandInteger:\n        ExpandIntegerResult(N, i);\n        Changed = true;\n        goto NodeDone;\n      case TargetLowering::TypeSoftenFloat:\n        SoftenFloatResult(N, i);\n        Changed = true;\n        goto NodeDone;\n      case TargetLowering::TypeExpandFloat:\n        ExpandFloatResult(N, i);\n        Changed = true;\n        goto NodeDone;\n      case TargetLowering::TypeScalarizeVector:\n        ScalarizeVectorResult(N, i);\n        Changed = true;\n        goto NodeDone;\n      case TargetLowering::TypeSplitVector:\n        SplitVectorResult(N, i);\n        Changed = true;\n        goto NodeDone;\n      case TargetLowering::TypeWidenVector:\n        WidenVectorResult(N, i);\n        Changed = true;\n        goto NodeDone;\n      case TargetLowering::TypeSoftPromoteHalf:\n        SoftPromoteHalfResult(N, i);\n        Changed = true;\n        goto NodeDone;\n      }\n    }\n\nScanOperands:\n    // Scan the operand list for the node, handling any nodes with operands that\n    // are illegal.\n    {\n    unsigned NumOperands = N->getNumOperands();\n    bool NeedsReanalyzing = false;\n    unsigned i;\n    for (i = 0; i != NumOperands; ++i) {\n      if (IgnoreNodeResults(N->getOperand(i).getNode()))\n        continue;\n\n      const auto &Op = N->getOperand(i);\n      LLVM_DEBUG(dbgs() << \"Analyzing operand: \"; Op.dump(&DAG));\n      EVT OpVT = Op.getValueType();\n      switch (getTypeAction(OpVT)) {\n      case TargetLowering::TypeLegal:\n        LLVM_DEBUG(dbgs() << \"Legal operand\\n\");\n        continue;\n      case TargetLowering::TypeScalarizeScalableVector:\n        report_fatal_error(\n            \"Scalarization of scalable vectors is not supported.\");\n      // The following calls must either replace all of the node's results\n      // using ReplaceValueWith, and return \"false\"; or update the node's\n      // operands in place, and return \"true\".\n      case TargetLowering::TypePromoteInteger:\n        NeedsReanalyzing = PromoteIntegerOperand(N, i);\n        Changed = true;\n        break;\n      case TargetLowering::TypeExpandInteger:\n        NeedsReanalyzing = ExpandIntegerOperand(N, i);\n        Changed = true;\n        break;\n      case TargetLowering::TypeSoftenFloat:\n        NeedsReanalyzing = SoftenFloatOperand(N, i);\n        Changed = true;\n        break;\n      case TargetLowering::TypeExpandFloat:\n        NeedsReanalyzing = ExpandFloatOperand(N, i);\n        Changed = true;\n        break;\n      case TargetLowering::TypeScalarizeVector:\n        NeedsReanalyzing = ScalarizeVectorOperand(N, i);\n        Changed = true;\n        break;\n      case TargetLowering::TypeSplitVector:\n        NeedsReanalyzing = SplitVectorOperand(N, i);\n        Changed = true;\n        break;\n      case TargetLowering::TypeWidenVector:\n        NeedsReanalyzing = WidenVectorOperand(N, i);\n        Changed = true;\n        break;", "numLines": 150, "startLine": 200, "totalLines": 1048}}

